import numpy as np

def lookup_embedding(W_in, word_index):
    return W_in[word_index]

def run_practice():
    W_in = np.array([[1.0, 2.0], [3.0, 4.0]])
    assert np.allclose(lookup_embedding(W_in, 1), np.array([3.0, 4.0]))
    print('[PASS] Lookup checks succeeded.')

if __name__ == '__main__':
